}

log_warn() {
    if [ -n "$GITHUB_ACTIONS" ]; then
        echo "::warning::$*"
    else
        echo "[WARN] $*"
    fi
}

log_error() {
    if [ -n "$GITHUB_ACTIONS" ]; then
        echo "::error::$*"
    else
        echo "[ERROR] $*"
    fi >&2
}

